import { useEffect, useState } from "react";
import "./Projects.css";

const projectsData = [
  {
    id: 1,
    title: "Dairy To HOME Service",
    description:
      "A full-featured multivendor e-commerce platform with real-time chat and Stripe/PayPal integration.",
    url: "http://dairyfarmmilk-service.netlify.app/",
    category: "fullstack",
  },
  {
    id: 2,
    title: "KisanBazar",
    description:
      "A hackathon-winning platform connecting local farmers with buyers to promote sustainable agriculture.",
    url: "https://kisanbazar.vercel.app",
    category: "fullstack",
  },
  {
    id: 3,
    title: "Gher.com",
    description:
      "A real estate marketplace with advanced search filters, interactive map view, and admin management tools.",
    url: "https://gher.vercel.app",
    category: "fullstack",
  },
  {
    id: 4,
    title: "Armostore",
    description:
      "A sleek, responsive e-commerce website for a clothing brand with product filtering and seamless UX.",
    url: "https://armostore.ca",
    category: "frontend",
  },
  {
    id: 5,
    title: "Goal Pulse",
    description:
      "A goal-setting and tracking app focused on simplicity, clarity, and consistency for personal growth.",
    url: "https://goalpulse.vercel.app",
    category: "fullstack",
  },
  {
    id: 6,
    title: "Book Dock",
    description:
      "A clean CRUD app for managing, searching, and organizing books by title or author.",
    url: "https://bookdock.vercel.app",
    category: "fullstack",
  },
  {
    id: 7,
    title: "Roomista",
    description:
      "A rental room discovery platform with intuitive filters and a mobile-first responsive UI.",
    url: "https://roomista.netlify.app",
    category: "frontend",
  },
  {
    id: 8,
    title: "Fit Club",
    description:
      "A fitness website with structured content and modern UI for health-focused audiences.",
    url: "https://thefitclub-web.netlify.app",
    category: "frontend",
  },
  {
    id: 9,
    title: "Color Craft",
    description:
      "A tool for designers to explore colors, palettes, and transparency effects with ease.",
    url: "https://colorcraft-web.netlify.app/",
    category: "frontend",
  },
];

const Projects = () => {
  const projectsNav = [
    "All",
    ...new Set(projectsData.map((project) => project.category)),
  ];

  const [item, setItem] = useState({ name: "All" });
  const [projects, setProjects] = useState([]);

  useEffect(() => {
    if (item.name === "All") {
      setProjects(projectsData);
    } else {
      setProjects(
        projectsData.filter((project) => project.category === item.name)
      );
    }
  }, [item]);
  return (
    <section className="section portfolio__projects" id="projects">
      <h2 className="section__title">Projects</h2>
      <span className="section__subtitle">Most recent works</span>
      <div>
        <div className="projects__filters">
          {projectsNav.map((navText, index) => {
            return (
              <span
                className={
                  item.name === navText
                    ? "active__filters-item projects__filters-item"
                    : "projects__filters-item"
                }
                key={index}
                onClick={() => setItem({ name: navText })}
              >
                {navText}
              </span>
            );
          })}
        </div>
        <div className="projects__container container grid">
          {projects.map(({ id, title, url, description }) => {
            return (
              <div class="card" key={id}>
                <div class="content">
                  <div class="h6">{title}</div>
                  <p>{description}</p>
                  <a
                    href={url}
                    target="_blank"
                    rel="noreferrer"
                    className="project__button"
                  >
                    Demo{" "}
                    <i className="bx bx-right-arrow-alt project__button-icon" />
                  </a>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </section>
  );
};

export default Projects;
